// Filtros y flags de disponibilidad.
//   ?estado=activa|cerrada     → filtra por estado
//   ?incluir_archivadas=1      → incluye las soft-deleted (por defecto NO)
// La vista devuelve TODAS las promociones (incl. archivadas) desde la
// migración 2026-04-23_02; filtramos aquí para permitir reactivar desde la UI.
const wh = $('Webhook GET Promociones').first().json || {};
const q = wh.query || wh.params || {};
const incluirArch = q.incluir_archivadas === '1' || q.incluir_archivadas === 'true' || q.incluir_archivadas === 1 || q.incluir_archivadas === true;

const raw = ($input.all() || []).map(i => i.json).filter(x => x && x.id);
let out = incluirArch ? raw : raw.filter(x => !x.deleted_at);
if (q.estado) out = out.filter(p => p.estado === q.estado);

out = out.map(p => ({
  ...p,
  full: (p.libres_total || 0) <= 0,
  manana_disponible: (p.libres_manana || 0) > 0,
  tarde_disponible:  (p.libres_tarde  || 0) > 0,
  archivada: !!p.deleted_at
}));

// Orden: vivas primero (por fecha_inicio desc), luego archivadas.
out.sort((a, b) => {
  if (!!a.deleted_at !== !!b.deleted_at) return a.deleted_at ? 1 : -1;
  const da = a.fecha_inicio ? new Date(a.fecha_inicio).getTime() : 0;
  const db = b.fecha_inicio ? new Date(b.fecha_inicio).getTime() : 0;
  return db - da;
});

return [{ json: { promociones: out } }];

// Acciones soportadas:
//   create     → alta con nombre + plazas (estado=activa)
//   update     → edita nombre/descripcion/fecha/plazas/estado
//   archivar   → soft-delete (deleted_at=now). Antes era 'delete' — renombrado
//                por claridad y para que el verbo sugiera reversibilidad.
//   reactivar  → deshace archivar (deleted_at=null)
//   cerrar     → estado='cerrada' (NO archivar; la promoción sigue visible)
//
// Hemos RETIRADO 'delete' (hard delete) del webhook público — igual que en
// 21-hardware-pedidos. El borrado definitivo, si alguna vez hace falta, se
// hace en Supabase a mano con salvaguardas adicionales.
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const p = b.promocion || {};
const now = new Date().toISOString();
const errores = [];
const VALID = ['create', 'update', 'archivar', 'reactivar', 'cerrar'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);
// UUID v4 laxo — evita IDs basura que generarían errores 22P02 confusos.
if (p.id && !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(p.id)) {
  errores.push('id no es un UUID válido');
}

let out = {};
if (action === 'create') {
  if (!p.nombre || !String(p.nombre).trim()) errores.push('nombre obligatorio');
  const pm = Number.isFinite(+p.plazas_manana) ? +p.plazas_manana : 8;
  const pt = Number.isFinite(+p.plazas_tarde)  ? +p.plazas_tarde  : 8;
  if (pm < 0 || pm > 100) errores.push('plazas_manana fuera de rango (0..100)');
  if (pt < 0 || pt > 100) errores.push('plazas_tarde fuera de rango (0..100)');
  // Generamos el id aquí (igual que en 21-hardware-pedidos) para que el
  // HTTP POST a PostgREST tenga PK explícita y no dependa de defaults.
  const _uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16); });
  out = {
    id: _uuid,
    nombre: String(p.nombre || '').trim(),
    descripcion: p.descripcion != null ? String(p.descripcion) : null,
    fecha_inicio: p.fecha_inicio || null,
    estado: p.estado === 'cerrada' ? 'cerrada' : 'activa',
    plazas_manana: pm,
    plazas_tarde: pt,
    created_by: p.created_by ? String(p.created_by) : null,
    created_at: now,
    updated_at: now
  };
} else if (action === 'update') {
  out.id = p.id;
  if (p.nombre       !== undefined) {
    if (!String(p.nombre).trim()) errores.push('nombre no puede ser vacío');
    else out.nombre = String(p.nombre).trim();
  }
  if (p.descripcion  !== undefined) out.descripcion  = p.descripcion ? String(p.descripcion) : null;
  if (p.fecha_inicio !== undefined) out.fecha_inicio = p.fecha_inicio || null;
  if (p.estado       !== undefined) {
    if (!['activa','cerrada'].includes(p.estado)) errores.push('estado debe ser activa|cerrada');
    else out.estado = p.estado;
  }
  if (p.plazas_manana !== undefined) {
    const pm = +p.plazas_manana;
    if (!Number.isFinite(pm) || pm < 0 || pm > 100) errores.push('plazas_manana fuera de rango (0..100)');
    else out.plazas_manana = pm;
  }
  if (p.plazas_tarde !== undefined) {
    const pt = +p.plazas_tarde;
    if (!Number.isFinite(pt) || pt < 0 || pt > 100) errores.push('plazas_tarde fuera de rango (0..100)');
    else out.plazas_tarde = pt;
  }
  out.updated_at = now;
} else if (action === 'archivar') {
  out = { id: p.id, deleted_at: now, updated_at: now };
} else if (action === 'reactivar') {
  out = { id: p.id, deleted_at: null, updated_at: now };
} else if (action === 'cerrar') {
  out = { id: p.id, estado: 'cerrada', updated_at: now };
}

Object.keys(out).forEach(k => { if (out[k] === undefined) delete out[k]; });

if (errores.length > 0) {
  return [{ json: { __error: true, __errores: errores, __action: action, __method: 'POST', __qs: 'on_conflict=id' } }];
}
// POST para create, PATCH por id para el resto.
const _method = (action === 'create') ? 'POST' : 'PATCH';
const _qs = (action === 'create') ? 'on_conflict=id' : ('id=eq.' + encodeURIComponent(p.id || ''));
return [{ json: Object.assign({}, out, { __method: _method, __qs: _qs }) }];

// Normaliza la salida PostgREST al shape único del frontend:
//   { success, promocion, errores }
// Precedencia: errores de validación del nodo Preparar > errores HTTP > filas.
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, promocion: null, errores: prep.__errores || ['validación falló'] } }];
}
const items = $input.all() || [];
const errores = [];
let rows = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  // PostgREST error shape: {code, message, details, hint}
  if (j.code && j.message && !j.id) {
    errores.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
    continue;
  }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.id) rows.push(j);
  if (Array.isArray(j.data)) rows = rows.concat(j.data);
}
if (rows.length === 0 && errores.length === 0) errores.push('PostgREST devolvió 0 filas');
return [{ json: {
  success: rows.length > 0,
  promocion: rows[0] || null,
  errores
} }];
